async (page) => {
  const asciiMap = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    return m && !m.error ? m.ascii.split('\n').slice(0, 20).join('\n') + '\n\n' + m.legendText : 'no map';
  });
  return asciiMap;
}

async (page) => {
  // Try to find and click death screen elements
  const result = await page.evaluate(() => {
    // Check what death-related UI elements exist
    const deathScreen = document.getElementById('death');
    const respawnBtn = document.getElementById('respawn');
    const warpBtn = document.getElementById('death-warp');
    return {
      deathScreen: deathScreen ? { display: window.getComputedStyle(deathScreen).display, visible: deathScreen.style.display !== 'none' } : null,
      respawnBtn: respawnBtn ? { exists: true } : null,
      warpBtn: warpBtn ? { exists: true } : null,
      bodyClasses: document.body.className,
    };
  });
  return JSON.stringify(result);
}

async (page) => {
  await page.evaluate(() => {
    document.getElementById('respawn').click();
  });
  await page.waitForTimeout(2000);
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({
      pos: s.player_position,
      stats: s.player_stats,
      is_dead: s.ui_state ? s.ui_state.is_dead : null,
      deathDisplay: document.getElementById('death') ? window.getComputedStyle(document.getElementById('death')).display : 'not found'
    });
  });
  return state;
}
